# Auto-generated compressed assets for Three.js Core. Do not edit.
import base64
import zlib

# Dictionary mapping URL paths to compressed data
LIBRARY_DATA = {
    "threejs/driver.css": "",
    "threejs/driver.js.iife.js": "",
    "threejs/three.js": "",
    "threejs/three.min.js": "",
    "threejs/three.module.js": "",
}

def get_library_asset(path):
    """Get a library asset by its URL path."""
    data = LIBRARY_DATA.get(path)
    if data:
        return zlib.decompress(base64.b64decode(data))
    return None

def has_library_asset(path):
    """Check if a library asset exists."""
    return path in LIBRARY_DATA
